# --- Models ---
class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(256), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True)  # Base32 secret for TOTP
    mfa_reset_token = db.Column(db.String(64), nullable=True, unique=True)
    mfa_reset_token_expiry = db.Column(db.DateTime, nullable=True)

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def generate_mfa_secret(self):
        self.mfa_secret = pyotp.random_base32()
        return self.mfa_secret

    def get_totp_uri(self):
        if not self.mfa_secret:
            return None
        return pyotp.totp.TOTP(self.mfa_secret).provisioning_uri(
            self.email, issuer_name="Flask MFA App"
        )

    def verify_totp(self, otp_code):
        if not self.mfa_secret:
            return False
        totp = pyotp.TOTP(self.mfa_secret)
        return totp.verify(otp_code)

    def generate_reset_token(self):
        self.mfa_reset_token = secrets.token_urlsafe(32)
        self.mfa_reset_token_expiry = datetime.utcnow() + timedelta(
            minutes=app.config["MFA_RESET_TOKEN_EXPIRY_MINUTES"]
        )
        db.session.add(self)
        db.session.commit()
        return self.mfa_reset_token

    @staticmethod
    def verify_reset_token(token):
        user = User.query.filter_by(mfa_reset_token=token).first()
        if user and user.mfa_reset_token_expiry > datetime.utcnow():
            return user
        return None

    def __repr__(self):
        return f"<User {self.email}>"


@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))


# --- Forms ---
class RegistrationForm(FlaskForm):
    email = StringField("Email", validators=[DataRequired(), Email()])
    password = PasswordField(
        "Password", validators=[DataRequired(), Length(min=6, max=50)]
    )
    confirm_password = PasswordField(
        "Confirm Password", validators=[DataRequired(), EqualTo("password")]
    )
    submit = SubmitField("Register")

    def validate_email(self, email):
        user = User.query.filter_by(email=email.data).first()
        if user:
            raise ValidationError(
                "That email is already registered. Please choose a different one."
            )


class LoginForm(FlaskForm):
    email = StringField("Email", validators=[DataRequired(), Email()])
    password = PasswordField("Password", validators=[DataRequired()])
    remember_me = BooleanField("Remember Me")
    submit = SubmitField("Log In")


class MFACodeForm(FlaskForm):
    otp_code = StringField("MFA Code", validators=[DataRequired(), Length(min=6, max=6)])
    submit = SubmitField("Verify")


class ResetMFAForm(FlaskForm):
    email = StringField("Email", validators=[DataRequired(), Email()])
    submit = SubmitField("Request MFA Reset")


# --- Routes ---
@app.before_request
def create_tables():
    db.create_all()


@app.route("/")
def index():
    if current_user.is_authenticated:
        return redirect(url_for("profile"))
    return render_template("index.html")


@app.route("/register", methods=["GET", "POST"])
def register():
    form = RegistrationForm()
    if form.validate_on_submit():
        user = User(email=form.email.data)
        user.set_password(form.password.data)
        db.session.add(user)
        db.session.commit()
        flash("Account created successfully! You can now log in.", "success")
        return redirect(url_for("login"))
    return render_template("register.html", form=form)


@app.route("/login", methods=["GET", "POST"])
def login():
    form = LoginForm()
    if form.validate_on_submit():
        user = User.query.filter_by(email=form.email.data).first()
        if user and user.check_password(form.password.data):
            if user.mfa_enabled:
                # Store user_id temporarily in session to allow MFA verification
                # This is a common pattern for two-step authentication
                request.args = {"user_id": user.id} # Pass user ID to MFA verification
                return redirect(url_for("verify_mfa"))
            else:
                login_user(user, remember=form.remember_me.data)
                flash("Logged in successfully!", "success")
                return redirect(url_for("profile"))
        else:
            flash("Invalid email or password", "danger")
    return render_template("login.html", form=form)


@app.route("/verify-mfa", methods=["GET", "POST"])
def verify_mfa():
    # User ID is passed from the login route temporarily
    user_id = request.args.get("user_id")
    if not user_id:
        flash("Something went wrong with your login attempt. Please try again.", "danger")
        return redirect(url_for("login"))

    user = User.query.get(user_id)
    if not user or not user.mfa_enabled:
        flash("MFA not enabled or user not found.", "danger")
        return redirect(url_for("login"))

    form = MFACodeForm()
    if form.validate_on_submit():
        if user.verify_totp(form.otp_code.data):
            login_user(user) # Log the user in after successful MFA verification
            flash("Logged in successfully with MFA!", "success")
            return redirect(url_for("profile"))
        else:
            flash("Invalid MFA code.", "danger")
    return render_template("verify_mfa.html", form=form)


@app.route("/profile")
@login_required
def profile():
    return render_template("profile.html", user=current_user)


@app.route("/mfa/setup", methods=["GET", "POST"])
@login_required
def mfa_setup():
    if current_user.mfa_enabled:
        flash("MFA is already enabled.", "info")
        return redirect(url_for("profile"))

    if not current_user.mfa_secret:
        # Generate a new secret if one doesn't exist for the current user
        current_user.generate_mfa_secret()
        db.session.add(current_user)
        db.session.commit()

    totp_uri = current_user.get_totp_uri()

    # Generate QR code image (Base64 encoded)
    qr = qrcode.QRCode(version=1, error_correction=qrcode.constants.ERROR_CORRECT_L, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")

    # Add text to the QR code image (optional, for better UX)
    # This might require some font files if running in a headless environment without default fonts
    try:
        draw = ImageDraw.Draw(img)
        font = ImageFont.truetype("arial.ttf", 20) # You might need to specify a font path
        text = "Scan with Authenticator"
        text_width, text_height = draw.textsize(text, font)
        img_width, img_height = img.size
        draw.text(((img_width - text_width) / 2, img_height - text_height - 10), text, font=font, fill="black")
    except Exception as e:
        print(f"Could not add text to QR code (font issue?): {e}")


    buffered = io.BytesIO()
    img.save(buffered, format="PNG")
    qr_code_base64 = base64.b64encode(buffered.getvalue()).decode("utf-8")

    form = MFACodeForm()
    if form.validate_on_submit():
        if current_user.verify_totp(form.otp_code.data):
            current_user.mfa_enabled = True
            db.session.add(current_user)
            db.session.commit()
            flash("MFA enabled successfully!", "success")
            return redirect(url_for("profile"))
        else:
            flash("Invalid MFA code. Please try again.", "danger")

    return render_template(
        "mfa_setup.html",
        form=form,
        qr_code_base64=qr_code_base64,
        secret=current_user.mfa_secret,
    )


@app.route("/mfa/disable", methods=["GET", "POST"])
@login_required
def mfa_disable():
    if not current_user.mfa_enabled:
        flash("MFA is not enabled.", "info")
        return redirect(url_for("profile"))

    if request.method == "POST":
        current_user.mfa_enabled = False
        current_user.mfa_secret = None  # Invalidate old secret
        db.session.add(current_user)
        db.session.commit()
        flash("MFA has been disabled.", "success")
        return redirect(url_for("profile"))
    return render_template("mfa_disable.html")


@app.route("/logout")
@login_required
def logout():
    logout_user()
    flash("You have been logged out.", "info")
    return redirect(url_for("index"))


@app.route("/reset-mfa", methods=["GET", "POST"])
def reset_mfa_request():
    form = ResetMFAForm()
    if form.validate_on_submit():
        user = User.query.filter_by(email=form.email.data).first()
        if user:
            token = user.generate_reset_token()
            reset_link = url_for("reset_mfa_confirm", token=token, _external=True)
            send_email(
                user.email,
                "MFA Reset Request",
                f"You have requested to reset your MFA settings.\n"
                f"Click the link to disable MFA: {reset_link}\n"
                f"This link will expire in {app.config['MFA_RESET_TOKEN_EXPIRY_MINUTES']} minutes.\n"
                f"If you did not request this, please ignore this email.",
            )
            flash(
                "If an account with that email exists, an MFA reset link has been sent to it.",
                "info",
            )
        else:
            # Provide a generic message to prevent email enumeration
            flash(
                "If an account with that email exists, an MFA reset link has been sent to it.",
                "info",
            )
        return redirect(url_for("login"))
    return render_template("reset_mfa_request.html", form=form)


@app.route("/reset-mfa/<token>")
def reset_mfa_confirm(token):
    user = User.verify_reset_token(token)
    if not user:
        flash("The MFA reset link is invalid or has expired.", "danger")
        return redirect(url_for("login"))

    # Disable MFA for the user
    user.mfa_enabled = False
    user.mfa_secret = None
    user.mfa_reset_token = None
    user.mfa_reset_token_expiry = None
    db.session.add(user)
    db.session.commit()

    flash(
        "Your MFA settings have been reset. You can now log in with just your password.",
        "success",
    )
    # Log the user in after resetting MFA for convenience in recovery flow
    # This aligns with "allows the user to log in with just password"
    login_user(user)
    return redirect(url_for("profile"))


